extension OutfitQueryWhereDistinct on QueryBuilder<Outfit, Outfit, QDistinct> {
  QueryBuilder<Outfit, Outfit, QDistinct> distinctByCover(
      {bool caseSensitive = true}) {
    return QueryBuilder.apply(this, (query) {
      return query.addDistinctBy(r'cover', caseSensitive: caseSensitive);
    });
  }

  QueryBuilder<Outfit, Outfit, QDistinct> distinctByCreateTime() {
    return QueryBuilder.apply(this, (query) {
      return query.addDistinctBy(r'createTime');
    });
  }

